import java.io.*;
import java.util.*;

public class Main {
    static final int INF = 1_000_000_000;

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append(' ');
        }
        String data = rawInput.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(data);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder output = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(st.nextToken());
            int[][] cost = new int[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    cost[i][j] = Integer.parseInt(st.nextToken());
                }
            }
            int ans = tsp(cost, N);
            output.append(ans);
            if (tc != T - 1) output.append('\n');
        }
        System.out.print(output.toString());
    }

    static int tsp(int[][] cost, int N) {
        int fullMask = (1 << N) - 1;
        int[][] dp = new int[1 << N][N];
        for (int[] row : dp) Arrays.fill(row, INF);
        dp[1][0] = 0; // start from city 0, visited only city 0
        for (int mask = 1; mask <= fullMask; mask++) {
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) == 0) continue;
                int cur = dp[mask][i];
                if (cur == INF) continue;
                for (int j = 0; j < N; j++) {
                    if ((mask & (1 << j)) != 0) continue;
                    int nextMask = mask | (1 << j);
                    int newCost = cur + cost[i][j];
                    if (newCost < dp[nextMask][j]) dp[nextMask][j] = newCost;
                }
            }
        }
        int ans = INF;
        for (int i = 0; i < N; i++) {
            if (dp[fullMask][i] < INF) {
                ans = Math.min(ans, dp[fullMask][i] + cost[i][0]);
            }
        }
        return ans;
    }
}

